import{_ as i,o as a,c as e,a2 as n}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"ps、top、htop、lsof、ss、curl、grep、awk 与 sed","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/05-linux-network/02-linux-diagnostic-commands.md","filePath":"05-backend-data/notes/05-linux-network/02-linux-diagnostic-commands.md","lastUpdated":1784542968000}'),t={name:"05-backend-data/notes/05-linux-network/02-linux-diagnostic-commands.md"};function l(p,s,h,d,o,r){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="ps、top、htop、lsof、ss、curl、grep、awk-与-sed" tabindex="-1">ps、top、htop、lsof、ss、curl、grep、awk 与 sed <a class="header-anchor" href="#ps、top、htop、lsof、ss、curl、grep、awk-与-sed" aria-label="Permalink to &quot;ps、top、htop、lsof、ss、curl、grep、awk 与 sed&quot;">​</a></h1><p>现场诊断的目标是用最小影响取得可重复证据，逐层回答“哪个进程、哪个资源、哪个端点、哪个请求、哪个时间窗发生了什么”。</p><h2 id="_1-诊断前的安全边界" tabindex="-1">1. 诊断前的安全边界 <a class="header-anchor" href="#_1-诊断前的安全边界" aria-label="Permalink to &quot;1. 诊断前的安全边界&quot;">​</a></h2><p>先记录主机、容器或网络命名空间、时区、开始时间、影响对象和命令。读取不等于零风险：<code>strace</code>、抓包、完整环境变量、命令行和日志可能泄漏密码、令牌或用户数据；高频采样和无边界递归搜索会消耗 CPU、I/O 与终端内存。</p><p>安全规则：</p><ul><li>先限定 PID、端口、文件、时间窗和最大输出行数。</li><li>默认不使用 <code>sudo</code>；权限不足时说明缺失证据，再申请最小权限。</li><li>原始证据保存到权限为 <code>0600</code> 的受控目录，分享前脱敏。</li><li>不用 <code>kill</code>、<code>rm</code>、<code>truncate</code>、<code>sysctl -w</code> 等改变状态的动作代替诊断。</li><li>命令参数使用 <code>--</code> 终止选项，并给变量加双引号。</li></ul><h2 id="_2-ps-进程快照" tabindex="-1">2. ps：进程快照 <a class="header-anchor" href="#_2-ps-进程快照" aria-label="Permalink to &quot;2. ps：进程快照&quot;">​</a></h2><p><code>ps</code> 读取某一时刻的进程信息。GNU/procps <code>ps</code> 可选择字段和排序：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -eo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,ppid,user,stat,nlwp,%cpu,%mem,rss,etime,cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sort=-%cpu</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,21p&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,tid,psr,stat,%cpu,wchan:24,comm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table tabindex="0"><thead><tr><th>字段</th><th>含义与边界</th></tr></thead><tbody><tr><td><code>PID/PPID</code></td><td>进程与父进程 ID；会复用，需同时核对启动时间和命令</td></tr><tr><td><code>STAT</code></td><td><code>R</code> 可运行、<code>S</code> 可中断睡眠、<code>D</code> 不可中断睡眠、<code>T</code> 停止、<code>Z</code> zombie；附加字符有独立含义</td></tr><tr><td><code>%CPU</code></td><td>procps 常表示生命周期内 CPU 时间比例，不等于最近一秒瞬时值</td></tr><tr><td><code>RSS</code></td><td>当前驻留物理内存的近似值，不等于独占内存或泄漏量</td></tr><tr><td><code>ETIME</code></td><td>启动后经过时间，用于排除刚重启进程</td></tr><tr><td><code>WCHAN</code></td><td>睡眠时等待的内核符号，受权限和符号可用性影响</td></tr></tbody></table><p>macOS 的 BSD <code>ps</code> 不支持 GNU <code>--sort</code> 和部分字段，可用 <code>ps -axo pid,ppid,user,state,%cpu,%mem,etime,command | sort -k5 -nr</code>，但排序首行和字段语义需单独处理。</p><h2 id="_3-top-与-htop-连续采样" tabindex="-1">3. top 与 htop：连续采样 <a class="header-anchor" href="#_3-top-与-htop-连续采样" aria-label="Permalink to &quot;3. top 与 htop：连续采样&quot;">​</a></h2><p><code>top</code> 周期采集进程和系统状态。先观察负载、CPU 各状态、内存和任务数，再按 PID/线程定位。交互快捷键会因实现不同而变化，批处理更适合留证：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/top-sample.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第一轮 CPU 差值可能覆盖工具启动前较长窗口，比较后续轮次。<code>us</code> 是用户态 CPU，<code>sy</code> 是内核态，<code>id</code> 是空闲，<code>wa</code> 是 CPU 空闲时至少有未完成 I/O 的时间比例；<code>wa</code> 不是“磁盘利用率”。</p><p><code>htop</code> 提供树、线程和筛选界面，但输出不适合稳定脚本解析。诊断记录应保留选择条件与时间，而不是只截一张无法复现的图。</p><h2 id="_4-lsof-从进程到打开对象" tabindex="-1">4. lsof：从进程到打开对象 <a class="header-anchor" href="#_4-lsof-从进程到打开对象" aria-label="Permalink to &quot;4. lsof：从进程到打开对象&quot;">​</a></h2><p><code>lsof</code> 枚举进程打开的文件，包括普通文件、目录、pipe 和 socket：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,80p&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iTCP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +L1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,40p&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>-nP</code> 避免 DNS 和服务名解析，减少延迟和歧义；<code>-a</code> 表示条件相与，否则多个选择项可能是相或。<code>+L1</code> 查找链接数小于 1 的已打开文件，可定位“文件已删除但磁盘未释放”。完整枚举可能需要 root，但提升权限也会看到更多敏感路径。</p><p>macOS 也常有 <code>lsof</code>；Linux <code>/proc/$PID/fd</code> 是另一条直接路径，macOS 没有兼容的 <code>/proc</code>。</p><h2 id="_5-ss-监听、连接与-tcp-内部状态" tabindex="-1">5. ss：监听、连接与 TCP 内部状态 <a class="header-anchor" href="#_5-ss-监听、连接与-tcp-内部状态" aria-label="Permalink to &quot;5. ss：监听、连接与 TCP 内部状态&quot;">​</a></h2><p><code>ss</code> 是 Linux iproute2 工具，读取 socket 状态：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> state</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> established</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;( sport = :8080 or dport = :8080 )&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dst</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.0.2.10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><code>-l</code> 只看监听，<code>-a</code> 看监听和非监听。</li><li><code>-n</code> 保留数值地址/端口，避免名称解析。</li><li><code>-t/-u/-x</code> 分别选择 TCP、UDP、Unix socket。</li><li><code>-p</code> 显示进程，需要足够权限。</li><li><code>-i</code> 展示 TCP 内部信息，如 RTT、拥塞窗口、重传；字段依内核版本和状态而异。</li></ul><p>只看到 <code>0.0.0.0:8080</code> 表示该网络命名空间内所有本地 IPv4 地址监听，不证明防火墙、路由、容器端口映射或外部负载均衡可达。macOS 没有 <code>ss</code>，可用 <code>netstat -anv</code>、<code>lsof -nP -iTCP -sTCP:LISTEN</code>，参数不可直接照搬。</p><h2 id="_6-curl-分解请求阶段" tabindex="-1">6. curl：分解请求阶段 <a class="header-anchor" href="#_6-curl-分解请求阶段" aria-label="Permalink to &quot;6. curl：分解请求阶段&quot;">​</a></h2><p><code>curl</code> 可以验证 DNS、连接、TLS、HTTP 状态与响应体。探活命令必须同时限制连接和总时长：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fail-with-body</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --silent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --show-error</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --connect-timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/health-body.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --write-out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;code=%{response_code} remote=%{remote_ip} dns=%{time_namelookup} connect=%{time_connect} tls=%{time_appconnect} ttfb=%{time_starttransfer} total=%{time_total}\\n&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://example.com/health</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>时间单位是秒。<code>time_connect</code>、<code>time_appconnect</code> 等是从请求开始累计的时间，不应直接相加；阶段耗时需做差。<code>--fail-with-body</code> 让 HTTP 400 及以上返回失败退出码并保留响应体，但仍需验证业务 JSON。<code>-v</code> 会输出 header，Authorization/Cookie 可能泄漏；公开证据优先使用 <code>--trace-config ids,time</code> 等受控方式并脱敏。</p><p><code>--resolve example.com:443:127.0.0.1</code> 可绕过 DNS同时保留 URL 主机名、SNI 和 Host，用于区分 DNS 与服务问题。它不是生产修复，测试完应删除。</p><h2 id="_7-grep-按行筛选" tabindex="-1">7. grep：按行筛选 <a class="header-anchor" href="#_7-grep-按行筛选" aria-label="Permalink to &quot;7. grep：按行筛选&quot;">​</a></h2><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;request_id=abc-123&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;timeout|connection reset&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,50p&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -RIl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --exclude=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;*.gz&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;deprecated_key&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>-F</code> 把模式当固定字符串，避免 <code>.</code>、<code>[</code> 等正则元字符意外扩展；<code>-E</code> 使用扩展正则；<code>-n</code> 显示行号；<code>-I</code> 跳过二进制文件。模式或文件名可能以 <code>-</code> 开头，因此使用 <code>--</code>。对超大压缩日志、活跃写入文件或敏感目录要先限定范围。</p><h2 id="_8-awk-按记录与字段计算" tabindex="-1">8. awk：按记录与字段计算 <a class="header-anchor" href="#_8-awk-按记录与字段计算" aria-label="Permalink to &quot;8. awk：按记录与字段计算&quot;">​</a></h2><p><code>awk</code> 默认按行读记录、按空白分字段，变量和数值转换是动态的：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;$9 ~ /^[0-9]+$/ {count[$9]++} END {for (code in count) print code, count[code]}&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>真实访问日志若包含带空格的引号字段，简单 <code>$9</code> 可能不是状态码。稳定分析优先输出 JSON 日志并用 JSON 解析器；若使用 awk，要声明日志格式、locale 和字段分隔符。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LC_ALL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\t&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;NR &gt; 1 &amp;&amp; $3+0 &gt;= 1 {sum += $3; n++} END {if (n) printf &quot;mean_ms=%.2f\\n&quot;, sum/n; else print &quot;no_data&quot;}&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> metrics.tsv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>LC_ALL=C</code> 固定排序、字符类和小数点行为。必须处理空输入，避免除零或输出误导性的 0。</p><h2 id="_9-sed-选择与流式变换" tabindex="-1">9. sed：选择与流式变换 <a class="header-anchor" href="#_9-sed-选择与流式变换" aria-label="Permalink to &quot;9. sed：选择与流式变换&quot;">​</a></h2><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;20,40p&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s/(Authorization: Bearer )[A-Za-z0-9._-]+/\\1[REDACTED]/g&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trace.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>默认 sed 会打印每个处理后的 pattern space，<code>-n</code> 配合 <code>p</code> 只输出选择内容。不同实现的就地编辑参数差异明显：GNU 常用 <code>sed -i.bak</code>，BSD/macOS 常见 <code>sed -i &#39;&#39;</code>。诊断期间不要对原始日志就地修改；输出到新文件并限制权限。</p><h2 id="_10-工具组合与退出状态" tabindex="-1">10. 工具组合与退出状态 <a class="header-anchor" href="#_10-工具组合与退出状态" aria-label="Permalink to &quot;10. 工具组合与退出状态&quot;">​</a></h2><p>管道中默认退出状态常来自最后一个命令，前面的 <code>grep</code> 或 <code>curl</code> 失败可能被掩盖。Bash 脚本使用：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;request_id=abc-123&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,20p&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>grep</code> 退出 0 表示匹配、1 表示无匹配、2 表示错误；“无匹配”不一定是脚本故障。需要按业务语义显式分支。不要解析为人类展示而设计、受版本和 locale 影响的列；自动化长期采集优先 <code>/proc</code>、结构化 API、监控 exporter 或工具的机器格式。</p><h2 id="_11-完整案例-本机健康检查间歇超时" tabindex="-1">11. 完整案例：本机健康检查间歇超时 <a class="header-anchor" href="#_11-完整案例-本机健康检查间歇超时" aria-label="Permalink to &quot;11. 完整案例：本机健康检查间歇超时&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>服务应监听 <code>127.0.0.1:8080</code>。</li><li>监控在 10:20–10:25 报告 2 秒超时。</li><li>不能重启、抓取完整请求体或查看其他用户进程。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li><code>date -Ins</code> 记录时区和开始时间。</li><li><code>ss -lntp &#39;sport = :8080&#39;</code> 确认监听地址、PID；无进程字段时不立即 sudo。</li><li><code>ps -p PID -o pid,ppid,user,stat,%cpu,%mem,rss,etime,cmd</code> 核对身份与是否刚重启。</li><li>连续三次运行带 <code>--write-out</code> 的 curl，保存状态码、connect、TTFB 和 total，不保存含用户数据响应体。</li><li>若 connect 快而 TTFB 慢，检查该 PID 的线程/CPU；若 connect 本身慢或拒绝，检查 backlog、监听和重启日志。</li><li>用 <code>journalctl -u service --since &#39;10:20&#39; --until &#39;10:26&#39; --no-pager</code> 限定日志，再以固定 request ID 关联。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>证据显示 connect 约 1 ms，TTFB 在故障请求为 2 s，进程存在且 CPU 不高；应用日志同一 request ID 显示下游数据库超时。结论是应用等待下游，不是 DNS 或监听失败。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>在测试环境注入同样下游延迟，curl 的 connect 保持稳定而 TTFB 上升；移除注入后恢复。监控应分别记录 connect、TTFB 和业务状态。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若 <code>ss</code> 无监听，继续检查 unit 状态、网络命名空间和启动日志；不要因为 curl <code>connection refused</code> 就修改防火墙。若只有外部访问失败而 loopback 成功，从入口逐层检查目标 IP、路由、防火墙、容器发布和代理，不把本机成功当端到端成功。</p><h2 id="_12-练习与完成标准" tabindex="-1">12. 练习与完成标准 <a class="header-anchor" href="#_12-练习与完成标准" aria-label="Permalink to &quot;12. 练习与完成标准&quot;">​</a></h2><ol><li>启动一个仅监听 loopback 的本地 HTTP 服务，使用 <code>ss</code>、<code>lsof</code>、<code>ps</code> 建立 PID—端口—可执行文件证据链。</li><li>用 curl 输出各阶段累计时间，并正确计算 DNS、TCP、TLS、TTFB 阶段差值。</li><li>构造 TSV 指标，用 awk 输出样本数和均值，对空文件输出 <code>no_data</code>。</li><li>完成标准：所有命令有范围、超时、副作用说明；Linux 与 macOS 替代命令不混用；失败退出状态有分支。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://man7.org/linux/man-pages/man1/ps.1.html" target="_blank" rel="noreferrer">procps-ng：ps(1)、top(1)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man8/ss.8.html" target="_blank" rel="noreferrer">iproute2：ss(8)</a>（访问日期：2026-07-17）</li><li><a href="https://lsof.readthedocs.io/en/stable/manpage/" target="_blank" rel="noreferrer">lsof manual</a>（访问日期：2026-07-17）</li><li><a href="https://curl.se/docs/manpage.html" target="_blank" rel="noreferrer">curl command line manual</a>（访问日期：2026-07-17）</li><li><a href="https://www.gnu.org/software/grep/manual/grep.html" target="_blank" rel="noreferrer">GNU grep、gawk 与 sed manuals</a>（访问日期：2026-07-17）</li></ul>`,62)])])}const F=i(t,[["render",l]]);export{c as __pageData,F as default};
